// TestBatchEvaluationSuccess tests batch evaluation with multiple requests
func TestBatchEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	boolFlagKey := "bool-flag"
	variantFlagKey := "variant-flag"
	namespaceKey := "test-namespace"

	// Setup mocks for boolean flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          boolFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespaceKey, boolFlagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for variant flag
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          variantFlagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRules", store.matchContext(), storage.NewResource(namespaceKey, variantFlagKey)).
		Return([]*storage.EvaluationRule{}, nil)

	// Make batch request
	payload := map[string]interface{}{
		"requests": []map[string]interface{}{
			{
				"request_id":    "req1",
				"flag_key":      boolFlagKey,
				"entity_id":     "user123",
				"namespace_key": namespaceKey,
			},
			{
				"request_id":    "req2",
				"flag_key":      variantFlagKey,
				"entity_id":     "user456",
				"namespace_key": namespaceKey,
			},
		},
	}

	body, err := json.Marshal(payload)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", srv.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Assert response
	assert.Equal(t, http.StatusOK, resp.StatusCode)

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, 2, len(result.Responses))
	assert.NotEmpty(t, result.RequestDurationMillis)
}

// TestEvaluationNamespaceScoping tests that evaluations are correctly scoped to namespaces
func TestEvaluationNamespaceScoping(t *testing.T) {
	store := &mockEvaluationStore{}
	srv := setupEvaluationServer(t, store)
	defer srv.Close()

	flagKey := "namespace-scoped-flag"
	namespace1 := "namespace-1"
	namespace2 := "namespace-2"

	// Setup mocks for first namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace1,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace1, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Setup mocks for second namespace
	store.On("GetFlag", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return(&flipt.Flag{
			NamespaceKey: namespace2,
			Key:          flagKey,
			Enabled:      false,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil)

	store.On("GetEvaluationRollouts", store.matchContext(), storage.NewResource(namespace2, flagKey)).
		Return([]*storage.EvaluationRollout{}, nil)

	// Evaluate in first namespace
	payload1 := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace1,
	}

	body1, err := json.Marshal(payload1)
	require.NoError(t, err)

	resp1, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body1),
	)
	require.NoError(t, err)
	defer resp1.Body.Close()

	var result1 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp1.Body).Decode(&result1)
	require.NoError(t, err)
	assert.Equal(t, true, result1.Enabled)

	// Evaluate in second namespace
	payload2 := map[string]interface{}{
		"flag_key":      flagKey,
		"entity_id":     "user123",
		"namespace_key": namespace2,
	}

	body2, err := json.Marshal(payload2)
	require.NoError(t, err)

	resp2, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", srv.URL),
		"application/json",
		bytes.NewReader(body2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	var result2 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp2.Body).Decode(&result2)
	require.NoError(t, err)
	assert.Equal(t, false, result2.Enabled)
}

